Since a couple of days I'm using the following monkey patch that apparently implements the same
semantic of Docker's .dockerignore. I don't know whether it's good/portable enough, but it
works quite well and it even comes with unittests.

Should you judge it positively, I'm willing to properly adapt it and open a PR.

```
#!/usr/bin/env python3
#

"""
This is quick&dirty attempt to workaround the non-conformant handling of
.dockerignore files of docker-py.

Python's fnmatch() uses a slightly different syntax, so it can't be used.

This tries to implement a behaviour closer to Docker CLI by translating the
file patterns (see http://golang.org/pkg/path/filepath#Match) into regexps.
"""

import os, re, unittest

from docker.utils import utils


def pattern_to_regexp(pattern):
    i = 0
    n = len(pattern)

    regexp = ''

    # Simplify by explicitly anchoring the pattern at root: accordingly to the
    # docker's refmanual, “/foo/bar and foo/bar both exclude a file or
    # directory named bar in the foo subdirectory”

    if pattern[0] == '!':
        if pattern[1] != '/':
            regexp += '/'
    elif pattern[0] != '/':
        regexp += '/'

    while i < n:
        c = pattern[i]
        i += 1
        if c == '\\':
            if i < n:
                regexp += re.escape(pattern[i])
                i += 1
            else:
                raise ValueError("Bad escape at index %d: %s" % (i, pattern))
        elif c == '*':
            if i < n and pattern[i] == '*':
                regexp = '.*'
                i += 1
            else:
                regexp = regexp + '[^/]*'
        elif c == '?':
            regexp = regexp + '[^/]'
        elif c == '[':
            regexp += c
            openpos = i-1
            while i < n:
                c = pattern[i]
                i += 1
                regexp += c
                if c == ']':
                    break
            else:
                raise ValueError("Unclosed '[' at index %d: %s"
                                 % (openpos, pattern))
        else:
            regexp = regexp + re.escape(c)

    return re.compile('^' + regexp + '$', re.DOTALL)


def dockerignore_patterns_as_regexps(patterns):
    repatterns = []
    for pattern in patterns:
        pattern = pattern.strip()
        if not pattern or pattern.startswith('#'):
            continue
        negated = False
        if pattern.startswith('!'):
            negated = True
            pattern = pattern[1:]
        repatterns.append((negated, pattern_to_regexp(pattern)))
    return repatterns


def valid(path, patterns):
    # Simplify by assuming all paths start with a slash,
    # that is are absolute within the root

    if not path.startswith('/'):
        path = '/' + path

    valid = True
    for negated, rx in patterns:
        if negated:
            if rx.match(path):
                valid = True
        else:
            if rx.match(path):
                valid = False
    return valid


def valid_paths(root, patterns, dockerfile=None,
                _exists=os.path.exists,
                _islink=os.path.islink,
                _join=os.path.join,
                _readlink=os.readlink,
                _relpath=os.path.relpath,
                _walk=os.walk):
    repatterns = dockerignore_patterns_as_regexps(patterns)

    if dockerfile is None:
        dockerfile = 'Dockerfile'

    # Be sure that the Dockerfile is always listed, even when
    # it's filtered out by the patterns

    dockerfile = _join(root, dockerfile)
    if _exists(dockerfile):
        dockerfile = _relpath(dockerfile, root)
        if not valid(dockerfile, repatterns):
            yield dockerfile

    for current_dir, subdirs, files in _walk(root):
        current_dir = _relpath(current_dir, root)

        if current_dir == '.':
            current_dir = ''

        subdirs[:] = [d for d in subdirs
                      if valid(_join(current_dir, d), repatterns)]

        if files or subdirs:
            for file in files:
                path = _join(current_dir, file)
                if valid(path, repatterns):
                    yield path

            # Since os.walk won't follow (by default) symlinks,
            # loop over directories accepting symlinks to valid paths

            for dir in subdirs:
                path = _join(current_dir, dir)
                fpath = _join(root, path)
                if _islink(fpath) and valid(path, repatterns):
                    linkto = _relpath(_readlink(fpath), root)
                    if linkto == '.':
                        linkto = ''
                    if valid(linkto, repatterns):
                        yield path
        else:
            # The directory is empty
            if valid(current_dir, repatterns):
                 yield current_dir


class TestPatternToRegexp(unittest.TestCase):
    cases = (
        ('A',
         ('/A',),
         ('/B',)),
        ('/A',
         ('/A',),
         ('/B',)),
        ('?/*.c',
         ('/a/x.c', '/x/abcz.c', '/a/.c'),
         ('/.c', '/ab/.c', '/a/.d', '/a//.d')),
        ('[^a-c]/?.c',
         ('/d/a.c', '/A/..c'),
         ('/a/b.c', '/xy/1.c')),
        ('**/.git',
         ('/.git', '/A/.git'),
         ('/x.git', '/a/b.git')),
    )

    def test_pattern_to_regexp(self):
        for pattern, should_match, should_not_match in self.cases:
            rep = pattern_to_regexp(pattern)
            for sm in should_match:
                self.assertTrue(rep.match(sm),
                                "%r should match %r" % (pattern, sm))
            for snm in should_not_match:
                self.assertFalse(rep.match(snm),
                                 "%r should match %r" % (pattern, snm))

    errors = (
        ('A\\', r'Bad escape at index 2:'),
        ('[A-B', r"Unclosed '\[' at index 0:"),
    )

    def test_bad_patterns(self):
        for pattern, msgrx in self.errors:
            with self.assertRaisesRegex(ValueError, msgrx):
                pattern_to_regexp(pattern)


class TestDockerignorePatternsAsRegexps(unittest.TestCase):
    cases = (
        (('A', '!B'),
         ((False, r'^/A$'),
          (True, r'^/B$'))),
    )

    def test_dockerignore_patterns_as_regexps(self):
        for dips, erxs in self.cases:
            rxs = dockerignore_patterns_as_regexps(dips)
            self.assertEqual(rxs, [(flag, re.compile(rx, re.DOTALL))
                                   for flag, rx in erxs])


class TestValid(unittest.TestCase):
    cases = (
        ('/app/.tox',
         ('*', '!app', 'app/.tox'),
         False),
        ('/app/config.tox',
         ('*', '!app', 'app/.tox'),
         True),
        ('/foo',
         ('*', '!app', 'app/.tox'),
         False),
        ('/foo/bar/.git',
         ('!foo', '**/.git'),
         False),
    )

    def test_valid(self):
        for path, dips, is_valid in self.cases:
            rxs = dockerignore_patterns_as_regexps(dips)
            self.assertEqual(valid(path, rxs), is_valid,
                             "%r against %r" % (path, dips))


class TestValidPaths(unittest.TestCase):
    mock_fs = (
        ('/', (('a', 'b', 'c', 'd', '.git'), ('a.txt', 'b.py'))),
        ('/a', (('.tox',), ('readme.txt',))),
        ('/a/.tox', (('dist', 'log', 'py35'), ())),
        ('/a/.tox/dist', ((), ())),
        ('/a/.tox/log', ((), ('tox-0.log'))),
        ('/a/.tox/py35', (('bin',), ('pip-selfcheck.json',))),
        ('/a/.tox/py35/bin', ((), ('pip',))),
        ('/b', ((), ('foo.c',))),
        ('/c', ((), ())),
        ('/d', (('symlinkto:../c',), ())),
        ('/.git', (('objects',), ('HEAD',))),
        ('/.git/objects', (('pack',), ())),
        ('/.git/objects/pack', ((), ('pack-1.idx', 'pack-1.pack'))),
    )

    def mock_walk(self, root):
        mock_fs = dict(self.mock_fs)
        queue = ['/']
        while queue:
            dir = queue.pop(0)
            dirs = list(mock_fs[dir][0])
            files = list(mock_fs[dir][1])
            yield dir, dirs, files
            queue = [os.path.join(dir, d) for d in dirs
                     if not self.mock_islink(d)] + queue

    def test_mock_walk(self):
        self.assertEqual(list(self.mock_walk('/')),
                         [(dir, list(dirs), list(files))
                          for dir, (dirs, files) in self.mock_fs])

    def mock_islink(self, path):
        return 'symlinkto:' in path

    def mock_readlink(self, path):
        assert self.mock_islink(path)
        head, _, tail = path.partition('/symlinkto:')
        return os.path.normpath(os.path.join(head, tail))

    cases = (
        (('*', '!a', '**/.git', '**/.tox'),
         ('a/readme.txt',)),
        (('**/.git', '**/.tox'),
         ('a.txt', 'b.py', 'a/readme.txt', 'b/foo.c', 'c', 'd/symlinkto:../c')),
        (('*', '![c-d]'),
         ('c', 'd/symlinkto:../c')),
        (('*', '!d'),
         ()),
    )

    def test_valid_paths(self):
        for dips, expected in self.cases:
            self.assertEqual(list(valid_paths('/', dips,
                                              _walk=self.mock_walk,
                                              _islink=self.mock_islink,
                                              _readlink=self.mock_readlink)),
                             list(expected))


def show_context():
    if os.path.exists('.dockerignore'):
        with open('.dockerignore', 'r') as f:
            patterns = f.read().splitlines()
    else:
        patterns = []
    for path in valid_paths(os.getcwd(), patterns):
        print(path)


def main():
    import sys
    if len(sys.argv) > 1 and sys.argv[1] == 'test':
        unittest.main(argv=sys.argv[:1], verbosity=2)
    elif len(sys.argv) > 1 and sys.argv[1] == 'context':
        show_context()
    else:
        utils.exclude_paths = valid_paths

        from compose.cli.main import main

        main()


if __name__ == '__main__':
    main()
```

Okay I think the bigger picture question is, should we let `raw()` be default behavior? My vote is apparently No because otherwise I'd have not even bothered to make it happen otherwise. 

To be more clear: conceptually, `input: $input`, `parameter: value` and `$output: output` are different, and do not have to be consistent. That is,

1. "input"'s value always starts with `$` to indicate output from another module; 
2. "output"'s value always takes a script variable, that is, `raw()` by default;
3. "parameter"'s value will always add quotes to unquoted string. Any script variables that tries to go into "parameter" must use `raw`. This is to make a clear case between constants (specified strings and numbers) vs. script variables. If we quote strings, it kind of make them stand out from numbers, and unquoted script variables will go un-noticed. This is why I dislike it.

I think this logic is clear. I may have failed to document them well, though.

