````
def pop_args(param):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            if param in kwargs:
                kwargs.pop(param)
            warnings.warn("This parameter {0} is deprecated and therefore was removed".format(param))
            return func(*args, **kwargs)
        return wrapper
    return decorator
````

